import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"إضافة قناة Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/yandex.md","filePath":"ar-SA/upload/yandex.md","lastUpdated":1781962217000}'),s={name:"ar-SA/upload/yandex.md"};function c(p,e,h,x,b,u){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="إضافة-قناة-yandex" tabindex="-1">إضافة قناة Yandex <a class="header-anchor" href="#إضافة-قناة-yandex" aria-label="Permalink to &quot;إضافة قناة Yandex&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-أولًا؟" tabindex="-1">ما الذي تحتاجه أولًا؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-أولًا؟" aria-label="Permalink to &quot;ما الذي تحتاجه أولًا؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>لماذا تحتاجه</th></tr></thead><tbody><tr><td>حساب Yandex</td><td>لتسجيل الدخول وتفويض Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>لإنشاء <code>Client ID</code> و <code>Client Secret</code></td></tr><tr><td>نطاق ImgBed الخاص بك</td><td>لاستخدامه في OAuth redirect URI</td></tr><tr><td>مساحة Yandex Disk متاحة</td><td>موقع التخزين الفعلي للملفات</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="الخطوة-1-أنشئ-yandex-oauth-app" tabindex="-1">الخطوة 1: أنشئ Yandex OAuth App <a class="header-anchor" href="#الخطوة-1-أنشئ-yandex-oauth-app" aria-label="Permalink to &quot;الخطوة 1: أنشئ Yandex OAuth App&quot;">​</a></h3><ol><li>افتح صفحة إنشاء Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>إذا تم تحويلك إلى تسجيل الدخول، فسجّل الدخول أولًا بحساب Yandex.</li><li>أنشئ app جديدًا.</li><li>أعطِ التطبيق اسمًا واضحًا، مثل <code>imgbed-yandex</code>.</li><li>ابحث عن إعدادات callback أو redirect URL.</li><li>أدخل:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="الخطوة-2-تأكد-من-الصلاحيات" tabindex="-1">الخطوة 2: تأكد من الصلاحيات <a class="header-anchor" href="#الخطوة-2-تأكد-من-الصلاحيات" aria-label="Permalink to &quot;الخطوة 2: تأكد من الصلاحيات&quot;">​</a></h3><p>لدمج Yandex الحالي في ImgBed، أبقِ هذه الصلاحيات الأربع ضمن <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>الغرض</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>يسمح لـ ImgBed بحفظ الملفات في app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>قراءة الملفات وروابط التنزيل</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>رفع الملفات وإنشاء المجلدات وحذف الملفات</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>قراءة حصة القرص والمساحة المستخدمة</td></tr></tbody></table><p>إذا ظهرت هذه الصلاحيات ضمن <code>Yandex ID API</code> فهي اختيارية:</p><table tabindex="0"><thead><tr><th>نص الصلاحية</th><th>التوصية</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>اختياري</td></tr><tr><td><code>Access to email address</code></td><td>اختياري</td></tr></tbody></table><p>تعتمد ميزات الرفع والتنزيل والحذف والحصص أساسًا على صلاحيات <code>Yandex.Disk REST API</code> الأربع أعلاه.</p><p><img src="'+t+'" alt="ضبط صلاحيات Yandex Disk" loading="lazy"></p><h3 id="الخطوة-3-انسخ-app-credentials" tabindex="-1">الخطوة 3: انسخ App Credentials <a class="header-anchor" href="#الخطوة-3-انسخ-app-credentials" aria-label="Permalink to &quot;الخطوة 3: انسخ App Credentials&quot;">​</a></h3><p>بعد إنشاء التطبيق انسخ:</p><table tabindex="0"><thead><tr><th>حقل Yandex</th><th>حقل ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="تسجيل Client ID و Secret" loading="lazy"></p><h3 id="الخطوة-4-املأ-قناة-yandex" tabindex="-1">الخطوة 4: املأ قناة Yandex <a class="header-anchor" href="#الخطوة-4-املأ-قناة-yandex" aria-label="Permalink to &quot;الخطوة 4: املأ قناة Yandex&quot;">​</a></h3><p>في إعدادات الرفع اختر <code>Yandex</code> واملأ:</p><table tabindex="0"><thead><tr><th>حقل ImgBed</th><th>ما الذي تدخله</th></tr></thead><tbody><tr><td>Channel name</td><td>اسم واضح، مثل <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> الخاص بتطبيق Yandex</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> الخاص بتطبيق Yandex</td></tr><tr><td>Refresh Token</td><td>اتركه فارغًا الآن</td></tr><tr><td>Root directory</td><td>اختياري. الافتراضي <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="تعديل إعداد القناة" loading="lazy"></p><h3 id="الخطوة-5-احصل-على-refresh-token" tabindex="-1">الخطوة 5: احصل على Refresh Token <a class="header-anchor" href="#الخطوة-5-احصل-على-refresh-token" aria-label="Permalink to &quot;الخطوة 5: احصل على Refresh Token&quot;">​</a></h3><ol><li>في ImgBed اضغط <code>Get Token</code>.</li><li>سجّل الدخول إلى حساب Yandex الذي تريد ربطه.</li><li>وافق على طلب التفويض.</li><li>ستعرض صفحة callback قيمة <code>Refresh Token</code>.</li><li>انسخها.</li><li>ارجع إلى ImgBed والصقها في حقل <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="نسخ refresh token بعد التفويض" loading="lazy"></p><h3 id="الخطوة-6-احفظ-القناة" tabindex="-1">الخطوة 6: احفظ القناة <a class="header-anchor" href="#الخطوة-6-احفظ-القناة" aria-label="Permalink to &quot;الخطوة 6: احفظ القناة&quot;">​</a></h3><p>بعد ملء جميع الحقول احفظ القناة.</p><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; أنشئ app</span></span>
<span class="line"><span>-&gt; أضف https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; تأكد من صلاحيات Yandex Disk</span></span>
<span class="line"><span>-&gt; انسخ Client ID و Client Secret</span></span>
<span class="line"><span>-&gt; أدخل Client ID / Client Secret في ImgBed</span></span>
<span class="line"><span>-&gt; اضغط Get Token</span></span>
<span class="line"><span>-&gt; انسخ Refresh Token من صفحة callback</span></span>
<span class="line"><span>-&gt; الصقه في ImgBed واحفظ</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(s,[["render",c]]);export{g as __pageData,y as default};
